import{_ as a,a as l,b as n,c as i}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as t,o,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Google Drive Kanalı Ekleme","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/upload/google-drive.md","filePath":"tr-TR/upload/google-drive.md","lastUpdated":1781962217000}'),s={name:"tr-TR/upload/google-drive.md"};function c(p,e,u,h,g,k){return o(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="google-drive-kanalı-ekleme" tabindex="-1">Google Drive Kanalı Ekleme <a class="header-anchor" href="#google-drive-kanalı-ekleme" aria-label="Permalink to &quot;Google Drive Kanalı Ekleme&quot;">​</a></h1><h2 id="once-gerekenler" tabindex="-1">Önce Gerekenler <a class="header-anchor" href="#once-gerekenler" aria-label="Permalink to &quot;Önce Gerekenler&quot;">​</a></h2><p>Başlamadan önce şunları hazırlayın:</p><table tabindex="0"><thead><tr><th>Gereken</th><th>Neden gerekir</th></tr></thead><tbody><tr><td>Google hesabı</td><td>Google Cloud&#39;a erişmek ve Google Drive&#39;ı yetkilendirmek için</td></tr><tr><td>Google Cloud projesi</td><td>Drive API&#39;yi etkinleştirmek ve OAuth credentials oluşturmak için</td></tr><tr><td>OAuth 2.0 client</td><td>ImgBed&#39;in <code>Client ID</code>, <code>Client Secret</code> ve <code>Refresh Token</code> alması için</td></tr><tr><td>ImgBed alan adınız</td><td>OAuth redirect URI için. Gerçekte kullandığınız alan adıyla eşleşmelidir.</td></tr></tbody></table><h2 id="kurulum-adımları" tabindex="-1">Kurulum Adımları <a class="header-anchor" href="#kurulum-adımları" aria-label="Permalink to &quot;Kurulum Adımları&quot;">​</a></h2><h3 id="_1-google-drive-api-yi-etkinlestirin" tabindex="-1">1. Google Drive API&#39;yi Etkinleştirin <a class="header-anchor" href="#_1-google-drive-api-yi-etkinlestirin" aria-label="Permalink to &quot;1. Google Drive API&#39;yi Etkinleştirin&quot;">​</a></h3><ol><li>Google Cloud Console&#39;u açın.</li><li>Yeni proje oluşturun veya mevcut bir projeyi seçin.</li><li><code>APIs &amp; Services</code> bölümüne gidin.</li><li><code>Enable APIs and Services</code> düğmesine tıklayın.</li><li><code>Google Drive API</code> araması yapın.</li><li>Açıp enable düğmesine tıklayın.</li></ol><h3 id="_2-oauth-consent-screen-i-yapılandırın" tabindex="-1">2. OAuth Consent Screen&#39;i Yapılandırın <a class="header-anchor" href="#_2-oauth-consent-screen-i-yapılandırın" aria-label="Permalink to &quot;2. OAuth Consent Screen&#39;i Yapılandırın&quot;">​</a></h3><ol><li>Google Cloud&#39;da <code>Google Auth Platform</code> bölümünü açın.</li><li>App adı, support email ve developer contact email gibi temel <code>Branding</code> bilgilerini doldurun.</li><li><code>Audience</code> bölümünü açın.</li><li>Çoğu self-hosted kişisel kurulum için <code>External</code> seçin.</li><li><code>External</code> seçtiyseniz yetkilendirmek istediğiniz Google hesabını <code>Test users</code> altına ekleyin.</li><li><code>Data Access</code> bölümünü açın.</li><li>Gerekli Google Drive permissions değerlerini ekleyin.</li></ol><h3 id="_3-oauth-2-0-client-olusturun" tabindex="-1">3. OAuth 2.0 Client Oluşturun <a class="header-anchor" href="#_3-oauth-2-0-client-olusturun" aria-label="Permalink to &quot;3. OAuth 2.0 Client Oluşturun&quot;">​</a></h3><ol><li><code>Google Auth Platform</code> içinde <code>Clients</code> bölümünü açın.</li><li>Yeni client oluşturun.</li><li>Application type değerini <code>Web application</code> yapın.</li><li>Client için tanınabilir bir ad verin.</li><li>Authorized JavaScript origins için ImgBed URL&#39;nizi girin, örneğin:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>Authorized redirect URIs için şunu girin:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+a+'" alt="OAuth client oluşturma" loading="lazy"></p><p><img src="'+l+'" alt="Alan adı ve callback URL girme" loading="lazy"></p><p>Client oluşturulduktan sonra şu değerleri kopyalayın:</p><table tabindex="0"><thead><tr><th>Oluşturulan Değer</th><th>ImgBed Alanı</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="_4-google-drive-kanalını-doldurun" tabindex="-1">4. Google Drive Kanalını Doldurun <a class="header-anchor" href="#_4-google-drive-kanalını-doldurun" aria-label="Permalink to &quot;4. Google Drive Kanalını Doldurun&quot;">​</a></h2><p>Yükleme Ayarları&#39;nda <code>Google Drive</code> seçin ve şunları doldurun:</p><table tabindex="0"><thead><tr><th>ImgBed Alanı</th><th>Ne girilir</th></tr></thead><tbody><tr><td>Channel name</td><td>Tanınabilir bir ad, örneğin <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Google Cloud&#39;dan alınan Client ID</td></tr><tr><td>Client Secret</td><td>Google Cloud&#39;dan alınan Client Secret</td></tr><tr><td>Refresh Token</td><td>Şimdilik boş bırakın. Sonraki adımda alınır.</td></tr><tr><td>Root directory</td><td>İsteğe bağlı. Varsayılan <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+n+'" alt="Client bilgilerini ImgBed&#39;e yapıştırma" loading="lazy"></p><h2 id="_5-refresh-token-alın" tabindex="-1">5. Refresh Token Alın <a class="header-anchor" href="#_5-refresh-token-alın" aria-label="Permalink to &quot;5. Refresh Token Alın&quot;">​</a></h2><ol><li><code>Get Token</code> düğmesine tıklayın.</li><li>Bağlamak istediğiniz Google hesabını seçin.</li><li>Yetkilendirme istemlerini tamamlayın.</li><li>Callback sayfası bir <code>Refresh Token</code> gösterir.</li><li>Bunu kopyalayın.</li><li>ImgBed&#39;e dönüp <code>Refresh Token</code> alanına yapıştırın.</li></ol><p><img src="'+i+`" alt="Yetkilendirme sonrası Refresh Token kopyalama" loading="lazy"></p><p>Daha sonra Google hesabını, OAuth client&#39;ı değiştirirseniz veya eski yetkilendirme süresi dolarsa kanalı silmeniz gerekmez. Düzenleme sayfasını açıp <code>Reauthorize</code> düğmesine tıklayın.</p><h2 id="_6-kanalı-kaydedin" tabindex="-1">6. Kanalı Kaydedin <a class="header-anchor" href="#_6-kanalı-kaydedin" aria-label="Permalink to &quot;6. Kanalı Kaydedin&quot;">​</a></h2><p>Tüm alanlar dolduktan sonra kanalı kaydedin.</p><h2 id="kısa-akıs" tabindex="-1">Kısa Akış <a class="header-anchor" href="#kısa-akıs" aria-label="Permalink to &quot;Kısa Akış&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Google Cloud&#39;u aç</span></span>
<span class="line"><span>-&gt; Proje oluştur veya seç</span></span>
<span class="line"><span>-&gt; Google Drive API&#39;yi etkinleştir</span></span>
<span class="line"><span>-&gt; Google Auth Platform&#39;u yapılandır</span></span>
<span class="line"><span>-&gt; Audience External ise Google hesabını Test users&#39;a ekle</span></span>
<span class="line"><span>-&gt; Web application OAuth client oluştur</span></span>
<span class="line"><span>-&gt; Redirect URI olarak https://your-domain.com/api/oauth/google/callback kullan</span></span>
<span class="line"><span>-&gt; Client ID ve Client Secret değerlerini ImgBed&#39;e gir</span></span>
<span class="line"><span>-&gt; Get Token tıkla</span></span>
<span class="line"><span>-&gt; Google ile giriş yap ve yetkilendir</span></span>
<span class="line"><span>-&gt; Callback sayfasından Refresh Token kopyala</span></span>
<span class="line"><span>-&gt; ImgBed&#39;e yapıştır ve kaydet</span></span>
<span class="line"><span>-&gt; Test görseli yükle</span></span></code></pre></div><h2 id="kaynaklar" tabindex="-1">Kaynaklar <a class="header-anchor" href="#kaynaklar" aria-label="Permalink to &quot;Kaynaklar&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const v=t(s,[["render",c]]);export{y as __pageData,v as default};
